mapper.insert:
INSERT INTO STOCSMSC (
        SMS_SEND_NUM
      , CELL_PHONE_NUM
      , SMS_SEND_STRING
      , SMS_SEND_DATE
) VALUES (
        #{KEY}
      , #{CELL_NUM}
      , #{CERTIFIED_NUMBER}
      , SYSDATE
)

MERGE INTO STOCTVUR A USING (SELECT #{GATE_CD} AS GATE_CD , UPPER((SF_TRIM(#{USER_ID}))) AS USER_ID FROM DUAL) B ON (A.GATE_CD = B.GATE_CD AND A.USER_ID = B.USER_ID) WHEN NOT MATCHED THEN INSERT ( GATE_CD , USER_ID , REG_DATE , CR_DATETIME , ENTRY_GB , REG_USER_ID , DEL_FLAG , COMPANY_CD , USE_FLAG , USER_TYPE , USER_NM , PASSWORD , EMAIL , CELL_NUM , PROGRESS_CD , PW_WRONG_CNT , PW_RESET_FLAG , PW_RESET_DATE , IP_ADDR , MNG_YN , SITE_USER_ID , GENDER , ZIP_CD , ADDR_1 , ADDR_2 , BIRTH_DATE , SMS_FLAG , MAIL_FLAG ) VALUES ( #{GATE_CD} , UPPER((SF_TRIM(#{USER_ID}))) , SYSDATE , SYSDATE , 'M' , UPPER((SF_TRIM(#{USER_ID}))) , '0' , '1002' , '1' , 'T' , #{USER_NM} , #{PASSWORD} , #{EMAIL} , #{CELL_NUM} , 'P' , '0' , '0' , SYSDATE , #{IP_ADDR} , '0' , #{SITE_USER_ID} , #{GENDER} , #{ZIP_CD} , #{ADDR} , #{ADDR_ETC} , #{BIRTH_DATE} , '1' , '1' ) WHEN MATCHED THEN UPDATE SET MOD_DATE = SYSDATE , MOD_USER_ID = UPPER((SF_TRIM(#{USER_ID}))) , USER_NM = #{USER_NM}
, GENDER = #{GENDER}
, PASSWORD = #{PASSWORD} , PW_RESET_DATE = SYSDATE
, CELL_NUM = #{CELL_NUM} , EMAIL = #{EMAIL} , ZIP_CD = #{ZIP_CD} , ADDR_1 = #{ADDR} , ADDR_2 = #{ADDR_ETC} , BIRTH_DATE =#{BIRTH_DATE} , SITE_USER_ID = #{SITE_USER_ID} , PROGRESS_CD = CASE WHEN PROGRESS_CD = 'E' THEN PROGRESS_CD ELSE 'P' END , USE_FLAG = '1' , USER_TYPE = 'T'

INSERT INTO STOCTUPW (
        GATE_CD
      , USER_ID
      , REG_DATE
      , REG_USER_ID
      , PASSWORD
      , REG_IP_ADDR
) VALUES (
        #{ses.gateCd}
      , UPPER((SF_TRIM(#{USER_ID})))
      , SYSDATE
      , #{USER_ID}
      , #{PASSWORD}
      , #{REG_IP_ADDR}
)

INSERT INTO EM_SMT_TRAN (
       MT_PR
     , DATE_CLIENT_REQ
     , SERVICE_TYPE
     , BROADCAST_YN
     , MSG_STATUS
     , CALLBACK      -- 발신자 전화번호
     , RECIPIENT_NUM -- 받는사람
     , CONTENT       -- 메세지
) VALUES (
       #{KEY}
     , SYSDATE
     , '0' --SERVICE_TYPE
     , 'N'
     , '1'
     , #{SEND_TEL_NUM}
     , #{RECV_TEL_NUM}
     , #{CERTIFIED_NUMBER}
)

mapper.update:
UPDATE STOCSMSC SET
        SMS_CONFIRM_DATE = SYSDATE
      , SMS_CONFIRM_FLAG = #{CONFIRM_FLAG}
 WHERE SMS_SEND_NUM = (SELECT MAX(SMS_SEND_NUM)
                          FROM STOCSMSC
                         WHERE CELL_PHONE_NUM = #{CELL_NUM}
                           AND SMS_SEND_STRING = #{CERTIFIED_NUMBER})
   AND CELL_PHONE_NUM = #{CELL_NUM}
   AND SMS_SEND_STRING = #{CERTIFIED_NUMBER}

UPDATE STOCTVUR SET MOD_DATE = SYSDATE , MOD_USER_ID = #{USER_ID} , PASSWORD = #{PASSWORD} , PW_RESET_FLAG = (#{PW_RESET_FLAG}, '0') , PW_RESET_DATE = SYSDATE , PW_WRONG_CNT = 0 , LAST_LOGIN_DATE = SYSDATE , BLOCK_FLAG = '0' , BLOCK_DATE = NULL WHERE UPPER(USER_ID) = UPPER(#{USER_ID})
AND UPPER(EMAIL) = UPPER(#{EMAIL})
AND GATE_CD = #{ses.gateCd}

UPDATE STOCTCCT SET
        MOD_DATE = SYSDATE
      , MOD_USER_ID = #{ses.userId}
      , PROGRESS_CD = '4300'
      , ATT_FILE_NUM = #{UUID}
      , SIGN_DATE = SYSDATE
      , EMP_SIGN_DATE = SYSDATE
      , EFORM_KEY = #{UUID}
 WHERE GATE_CD = #{ses.gateCd}
   AND BUYER_CD = #{BUYER_CD}
   AND CONT_NUM = #{CONT_NUM}
   AND CONT_CNT = #{CONT_CNT}
   AND USER_ID = #{ses.userId}

UPDATE STOCNOTC
   SET VIEW_CNT = VIEW_CNT + 1
 WHERE GATE_CD = #{ses.gateCd}
   AND NOTICE_NUM = #{noticeNo}

mapper.select:
SELECT COUNT(*) AS CONFIRM_FLAG
  FROM STOCSMSC
 WHERE SMS_SEND_NUM = (SELECT MAX(SMS_SEND_NUM)
                          FROM STOCSMSC
                         WHERE CELL_PHONE_NUM = #{CELL_NUM}
                           AND SMS_SEND_STRING = #{CERTIFIED_NUMBER})
   AND CELL_PHONE_NUM = #{CELL_NUM}
   AND SMS_SEND_STRING = #{CERTIFIED_NUMBER}
   AND TO_CHAR(SMS_SEND_DATE, 'YYYYMMDDHH24MISS') + 120  >  TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS')

SELECT A.*
FROM (
    SELECT PASSWORD
      FROM STOCTUPW
     WHERE 1 = 1
       AND USER_ID = #{USER_ID}
       AND GATE_CD = #{ses.gateCd}
     ORDER BY REG_DATE DESC
) A
WHERE ROWNUM  <=  2

SELECT COUNT(*)
  FROM STOCATCH
 WHERE GATE_CD = #{ses.gateCd}
   AND UUID = #{UUID}
   AND UUID_SQ = #{UUID_SQ}
   AND REG_USER_ID = #{ses.userId}
   AND DEL_FLAG = '0'
